import{_ as e,o as a,c as l,ag as d}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse('{"title":"Modern Tooling 别名 | Dotfiles (ZH)","titleTemplate":":title","description":"eza、bat 和 ripgrep 的现代 shell 别名。使用更快的基于 Rust 的替代品取代传统 Unix 工具。","frontmatter":{"title":"Modern Tooling 别名 | Dotfiles","description":"eza、bat 和 ripgrep 的现代 shell 别名。使用更快的基于 Rust 的替代品取代传统 Unix 工具。","lang":"zh-CN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Modern Tooling 别名 preview","canonical":"/zh/aliases/modern/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Modern Tooling 别名","pageType":"docs","schemaType":"WebPage","metaTitle":"Modern Tooling 别名 - Dotfiles (CN)","permalink":"/zh/aliases/modern/","sidebar":true,"meta":[{"name":"keywords","content":"现代别名, eza, bat, ripgrep, rust cli 工具, dotfiles, shell"}]},"headers":[],"relativePath":"zh/aliases/modern/index.md","filePath":"zh/aliases/modern/index.md","lastUpdated":1773010926000}'),o={name:"zh/aliases/modern/index.md"};function i(r,t,n,s,c,h){return a(),l("div",null,[...t[0]||(t[0]=[d('<h1 id="modern-tooling-别名" tabindex="-1">Modern Tooling 别名 <a class="header-anchor" href="#modern-tooling-别名" aria-label="Permalink to &quot;Modern Tooling 别名&quot;">​</a></h1><p>更快、更智能的传统 Unix 命令替代品。</p><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>定义在 <code>modern.aliases.sh</code> 中的现代别名提供了传统 Unix 工具的基于 Rust 的替代品。这些别名由 <code>chezmoi</code> 自动加载，当现代工具不可用时会优雅地回退到标准命令。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><h3 id="使用-eza-列出文件" tabindex="-1">使用 eza 列出文件 <a class="header-anchor" href="#使用-eza-列出文件" aria-label="Permalink to &quot;使用 eza 列出文件&quot;">​</a></h3><p>当安装了 <code>eza</code> 时替换 <code>ls</code>。</p><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">命令</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>ls</code></td><td style="text-align:left;"><code>eza --icons</code></td><td style="text-align:left;">带图标列出文件</td></tr><tr><td style="text-align:left;"><code>ll</code></td><td style="text-align:left;"><code>eza -alF</code></td><td style="text-align:left;">长列表格式</td></tr><tr><td style="text-align:left;"><code>la</code></td><td style="text-align:left;"><code>eza -a</code></td><td style="text-align:left;">列出所有文件（包括隐藏文件）</td></tr><tr><td style="text-align:left;"><code>lt</code></td><td style="text-align:left;"><code>eza --tree</code></td><td style="text-align:left;">显示目录树</td></tr></tbody></table><p>如果未安装 <code>eza</code>，则回退到标准 <code>ls</code>。</p><h3 id="使用-bat-查看文件内容" tabindex="-1">使用 bat 查看文件内容 <a class="header-anchor" href="#使用-bat-查看文件内容" aria-label="Permalink to &quot;使用 bat 查看文件内容&quot;">​</a></h3><p>当安装了 <code>bat</code> 时替换 <code>cat</code>。</p><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">命令</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>cat</code></td><td style="text-align:left;"><code>bat</code></td><td style="text-align:left;">显示带语法高亮的文件内容</td></tr></tbody></table><h3 id="使用-ripgrep-搜索" tabindex="-1">使用 ripgrep 搜索 <a class="header-anchor" href="#使用-ripgrep-搜索" aria-label="Permalink to &quot;使用 ripgrep 搜索&quot;">​</a></h3><p>当安装了 <code>rg</code> 时替换 <code>grep</code>。</p><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">命令</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>grep</code></td><td style="text-align:left;"><code>rg</code></td><td style="text-align:left;">使用 Ripgrep 搜索文件内容</td></tr></tbody></table>',15)])])}const f=e(o,[["render",i]]);export{p as __pageData,f as default};
